INSERT INTO tests (
    request_info_id, receipt_info_id, result_info_id, completion_info_id,
    user_id, product_id, stage, created_at, updated_at
)
VALUES (
           #{requestInfoId}, #{receiptInfoId}, #{resultInfoId}, #{completionInfoId},
           #{userId}, #{productId}, #{stage}, 
           #{createdAt}, #{updatedAt}
       )

mapper.select:
SELECT t.id, t.request_info_id, t.receipt_info_id, t.result_info_id, t.completion_info_id, t.user_id, t.product_id, t.stage, t.created_at, t.updated_at FROM tests t LEFT JOIN request_infos ri ON t.request_info_id = ri.id LEFT JOIN users u ON t.user_id = u.id
ri.title LIKE CONCAT('%', #{title}, '%')
AND u.username LIKE CONCAT('%', #{username}, '%')
AND t.stage = #{stage}
AND t.product_id = #{productId}
ORDER BY t.created_at DESC
